/**
 * Bytecode for InterchainAccountRouter compiled for Viction, which needs
 * two deviations from the SDK's default (Cancun-targeted) solc build:
 *
 * - `evm_version = 'london'`: Viction's EVM doesn't support post-London
 *   opcodes — notably PUSH0 (introduced in Solidity 0.8.20 / Shanghai).
 *   Using an unsupported opcode burns the entire gas limit as an
 *   invalid-opcode fault, indistinguishable from a plain out-of-gas.
 * - `optimizer_runs = 200`: Viction enforces go-ethereum's standard 32KB
 *   max tx size. Losing PUSH0 (and other Shanghai+/Cancun size
 *   optimizations) under `london` makes the default profile's
 *   `optimizer_runs = 10_000` (tuned for runtime gas, not size) push this
 *   contract's init code over that limit; 200 comes in comfortably under.
 *
 * The ABI is unchanged in both cases — only opcode-level codegen differs.
 * See solidity/foundry.toml `[profile.viction]`.
 *
 * Regenerate with:
 *   cd solidity && FOUNDRY_PROFILE=viction forge build contracts/middleware/InterchainAccountRouter.sol
 * then copy `.bytecode.object` from
 * out-viction/InterchainAccountRouter.sol/InterchainAccountRouter.json
 */
export const LEGACY_EVM_INTERCHAIN_ACCOUNT_ROUTER_BYTECODE =
  '';
